block.text:
$(".select2-contacts").select2({
    ajax: {
        url: "/ProjectDatabase/AddressBook/ContactSelect2",
        type: 'POST',
        dataType: 'json',
        delay: 250,
        data: function (params) {
            let postData = {
                q: params.term
            };

            // check for optional filter
            let filterKey = $(this).data('filter-key');
            let filterValue = $(this).data('filter-value');
            if (filterKey && filterValue !== undefined) {
                postData[filterKey] = filterValue;
            }

            return postData;
        },
        cache: false,
    },
    placeholder: '--- Select ---',
    minimumInputLength: 2,
    width: 'min(260px, 100%)'
})
